function buildPass22TextSections(slug: string, value: string, style: string) {
  const label = compactSeed(value, slug.includes('name') ? 'Avery Vale' : 'Hello World').slice(0, 32);
  const upper = label.toUpperCase();
  const scriptMap = unicodeMap(0x1D49C, 0x1D4B6);
  const boldScriptMap = unicodeMap(0x1D4D0, 0x1D4EA);
  const circledMap = unicodeMap(0x24B6, 0x24D0);
  const monoMap = monospaceUnicodeMap;
  const sectionsBySlug: Record<string, { title: string; body: string; note: string }[]> = {
    'big-text-generator': [
      { title: 'Block', body: upper.split('').map(char => char === ' ' ? '   ' : `[${char}]`).join(' '), note: 'Large plain-text block preview.' },
      { title: 'Banner', body: `==== ${upper} ====\n${upper.split('').join(' ')}\n==== ${'='.repeat(Math.max(6, upper.length))} ====`, note: 'Best for headers in notes or comments.' },
      { title: 'Stacked', body: upper.split(/\s+/).map(word => `# ${word}`).join('\n'), note: 'Readable on narrow mobile screens.' },
      { title: 'Outline', body: `+${'-'.repeat(upper.length + 2)}+\n| ${upper} |\n+${'-'.repeat(upper.length + 2)}+`, note: 'ASCII-only outline style.' }],
    'bubble-text-generator': [
      { title: 'Circled', body: toUnicode(label, circledMap), note: 'Decorative circled Unicode letters.' },
      { title: 'Filled', body: label.split('').map(char => /[a-z0-9]/i.test(char) ? `(${char})` : char).join(''), note: 'Compatibility-friendly bubble fallback.' },
      { title: 'Soft', body: `â—‹ ${label} â—‹\nâ—Œ ${label} â—Œ\nâ—Ž ${label} â—Ž`, note: 'Soft bubble decorations.' },
      { title: 'Mixed', body: `â“˜ ${toUnicode(label, circledMap)}\nBubble label: ${label}`, note: 'Profile and caption style.' }],
    'cursive-name-generator': [
      { title: 'Script', body: toUnicode(label, scriptMap), note: 'Decorative script Unicode.' },
      { title: 'Bold Script', body: toUnicode(label, boldScriptMap), note: 'Heavier decorative script.' },
      { title: 'Signature', body: `${toUnicode(label, scriptMap)}\n${label}\n${label.split(' ').map(part => part.charAt(0).toUpperCase()).join('. ')}.`, note: 'Name-card and signature variants.' },
      { title: 'Name Card', body: `${label}\n${toUnicode(label, scriptMap)}\n${toUnicode(label, italicUnicodeMap)}`, note: 'Compare readable and decorative forms.' }],
    'cute-text-generator': [
      { title: 'Soft', body: `â™¡ ${label} â™¡\n( ${label} )\nsoft note: ${label}`, note: 'Gentle caption styling.' },
      { title: 'Sparkle', body: `* ${label} *\nâœ¦ ${label} âœ¦\n. ${label} .`, note: 'Light decorative accents.' },
      { title: 'Caption', body: `${label}!\njust ${label.toLowerCase()} things\nlittle ${label.toLowerCase()} moment`, note: 'Short social captions.' },
      { title: 'Profile', body: `${label} club\nmade for ${label.toLowerCase()}\n${label} notes`, note: 'Profile-safe text ideas.' }],
    'pixel-text-generator': [
      { title: 'Pixel Box', body: upper.split('').map(char => char === ' ' ? '   ' : `[${char}]`).join(''), note: 'Pixel-like plain-text blocks.' },
      { title: 'Arcade', body: `> ${upper} <\n[ START ${upper} ]\n[ LEVEL: ${upper.slice(0, 12)} ]`, note: 'Arcade menu style.' },
      { title: 'Terminal', body: `$ load "${upper}"\n> status: ready\n> label: ${upper}`, note: 'Terminal-style output.' },
      { title: 'Compact', body: `:: ${upper} ::\n[${upper.replace(/\s+/g, '_')}]\n${toUnicode(upper, monoMap)}`, note: 'Compact pixel/mono variants.' }],
    'retro-text-generator': [
      { title: 'Arcade', body: `### ${upper} ###\nINSERT COIN: ${upper}\n1UP ${upper}`, note: 'Arcade-inspired plain text.' },
      { title: 'Poster', body: `*** ${upper} ***\nTonight: ${label}\nNow playing: ${label}`, note: 'Retro poster copy.' },
      { title: 'Vapor', body: `${transformFullwidth(label)}\n${upper.split('').join(' ')}\n- ${label} -`, note: 'Wide-spaced retro display.' },
      { title: 'Console', body: `READY > ${upper}\nRUN > ${upper.replace(/\s+/g, '_')}\nSAVE > ${upper.slice(0, 16)}`, note: 'Old-console style.' }]};
  const sections = sectionsBySlug[slug] ?? [];
  const selected = style === 'all' ? sections : sections.filter(section => slugWords(section.title).join('-') === style);
  return selected.length ? selected : sections;
}

