      const preview = cipher === 'atbash' ? atbash(cipherText) : caesar(cipherText, -amount);
      const mapping = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('').map(ch => `${ch}->${cipher === 'atbash' ? atbash(ch) : caesar(ch, amount)}`).join(' ');
